/// Stream a single-URL crawl, yielding `CrawlEvent`s as pages are processed.
///
/// Returns an async stream that emits one event per crawled page, plus a
/// terminal `Complete` event. On per-URL failure during the crawl, emits an
/// `Error` event followed by `Complete`. The stream item type is wrapped in
/// a `Result` to surface transport-level errors; today every emit is `Ok`.
///
/// Language bindings expose this as the native streaming shape for each
/// target. WASM does not expose native streaming wrappers.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn cberg_crawl_engine_handle_crawl_stream(
    client: *const crawlberg::CrawlEngineHandle,
    request_json: *const std::ffi::c_char,
    callback: CbergStreamCallback,
    user_data: *mut std::ffi::c_void,
) -> i32 {
    clear_last_error();

    if client.is_null() {
        set_last_error(99, "cberg_crawl_stream: client must not be NULL");
        return -1;
    }
    if request_json.is_null() {
        set_last_error(99, "cberg_crawl_stream: request_json must not be NULL");
        return -1;
    }

    // SAFETY: caller guarantees `client` and `request_json` are non-null and valid.
    let client_ref = unsafe { &(*client) };

    let json_str = match unsafe { std::ffi::CStr::from_ptr(request_json) }.to_str() {
        Ok(s) => s,
        Err(e) => {
            set_last_error(99, &format!("cberg_crawl_stream: request_json is not valid UTF-8: {e}"));
            return -1;
        }
    };

    let request: crawlberg::CrawlStreamRequest = match serde_json::from_str(json_str) {
        Ok(r) => r,
        Err(e) => {
            set_last_error(99, &format!("cberg_crawl_stream: failed to parse request JSON: {e}"));
            return -1;
        }
    };

    let rt = get_ffi_runtime();

    let result = rt.block_on(async {
        use futures_util::StreamExt;

        let mut stream = match client_ref.crawl_stream(request).await {
            Ok(s) => s,
            Err(e) => return Err(format!("cberg_crawl_stream: failed to open stream: {e}")),
        };

        loop {
            match stream.next().await {
                None => break,
                Some(Err(e)) => return Err(format!("cberg_crawl_stream: stream error: {e}")),
                Some(Ok(chunk)) => {
                    let chunk_json = match serde_json::to_string(&chunk) {
                        Ok(s) => s,
                        Err(e) => return Err(format!("cberg_crawl_stream: failed to serialise chunk: {e}")),
                    };
                    match std::ffi::CString::new(chunk_json) {
                        Ok(c_str) => {
                            // SAFETY: `callback` is a valid function pointer supplied by the caller.
                            // `c_str.as_ptr()` is valid for this block scope.
                            // `user_data` is forwarded as-is; ownership stays with the caller.
                            unsafe { callback(c_str.as_ptr(), user_data) };
                        }
                        Err(e) => return Err(format!("cberg_crawl_stream: chunk JSON contained NUL byte: {e}")),
                    }
                }
            }
        }
        Ok(())
    });

    match result {
        Ok(()) => 0,
        Err(e) => {
            set_last_error(99, &e);
            -1
        }
    }
}

/// Stream a multi-URL crawl, yielding `CrawlEvent`s across all seeds.
///
/// Returns an async stream that emits one event per crawled page across all
/// seeds, plus terminal `Complete` and `Error` events as appropriate. The
/// stream item type is wrapped in a `Result` to surface transport-level
/// errors; today every emit is `Ok`.
///
/// Language bindings expose this as the native streaming shape for each
/// target. WASM does not expose native streaming wrappers.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn cberg_crawl_engine_handle_batch_crawl_stream(
    client: *const crawlberg::CrawlEngineHandle,
    request_json: *const std::ffi::c_char,
    callback: CbergStreamCallback,
    user_data: *mut std::ffi::c_void,
) -> i32 {
    clear_last_error();

    if client.is_null() {
        set_last_error(99, "cberg_batch_crawl_stream: client must not be NULL");
        return -1;
    }
    if request_json.is_null() {
        set_last_error(99, "cberg_batch_crawl_stream: request_json must not be NULL");
        return -1;
    }

    // SAFETY: caller guarantees `client` and `request_json` are non-null and valid.
    let client_ref = unsafe { &(*client) };

    let json_str = match unsafe { std::ffi::CStr::from_ptr(request_json) }.to_str() {
        Ok(s) => s,
        Err(e) => {
            set_last_error(
                99,
                &format!("cberg_batch_crawl_stream: request_json is not valid UTF-8: {e}"),
            );
            return -1;
        }
    };

    let request: crawlberg::BatchCrawlStreamRequest = match serde_json::from_str(json_str) {
        Ok(r) => r,
        Err(e) => {
            set_last_error(
                99,
                &format!("cberg_batch_crawl_stream: failed to parse request JSON: {e}"),
            );
            return -1;
        }
    };

    let rt = get_ffi_runtime();

    let result = rt.block_on(async {
        use futures_util::StreamExt;

        let mut stream = match client_ref.batch_crawl_stream(request).await {
            Ok(s) => s,
            Err(e) => return Err(format!("cberg_batch_crawl_stream: failed to open stream: {e}")),
        };

        loop {
            match stream.next().await {
                None => break,
                Some(Err(e)) => return Err(format!("cberg_batch_crawl_stream: stream error: {e}")),
                Some(Ok(chunk)) => {
                    let chunk_json = match serde_json::to_string(&chunk) {
                        Ok(s) => s,
                        Err(e) => return Err(format!("cberg_batch_crawl_stream: failed to serialise chunk: {e}")),
                    };
                    match std::ffi::CString::new(chunk_json) {
                        Ok(c_str) => {
                            // SAFETY: `callback` is a valid function pointer supplied by the caller.
                            // `c_str.as_ptr()` is valid for this block scope.
                            // `user_data` is forwarded as-is; ownership stays with the caller.
                            unsafe { callback(c_str.as_ptr(), user_data) };
                        }
                        Err(e) => return Err(format!("cberg_batch_crawl_stream: chunk JSON contained NUL byte: {e}")),
                    }
                }
            }
        }
        Ok(())
    });

    match result {
        Ok(()) => 0,
        Err(e) => {
            set_last_error(99, &e);
            -1
        }
    }
}

