pub unsafe extern "C" fn cberg_ssrf_policy_from_env() -> *mut crawlberg::SsrfPolicy {
    clear_last_error();
    let result = crawlberg::SsrfPolicy::from_env();
    Box::into_raw(Box::new(result))
}

