fn get_ffi_runtime() -> &'static tokio::runtime::Runtime {
    use std::sync::OnceLock;
    static RUNTIME: OnceLock<tokio::runtime::Runtime> = OnceLock::new();
    RUNTIME.get_or_init(|| tokio::runtime::Runtime::new().expect("Failed to create tokio runtime"))
}

/// Convert markdown links to numbered citations.
///
/// `Example (https://example.com)` becomes `Example[1]`
/// with `[1]: https://example.com` in the reference list.
/// Images `!alt (url)` are preserved unchanged.
/// \note SAFETY: Caller must ensure all pointer arguments are valid or null. Returned pointers must be
/// freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn cberg_generate_citations(markdown: *const std::ffi::c_char) -> *mut crawlberg::CitationResult {
    clear_last_error();
    if markdown.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'markdown'");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees markdown is a valid pointer; string is valid UTF-8 from caller.
    let markdown_rs = match unsafe { CStr::from_ptr(markdown) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'markdown'");
            return std::ptr::null_mut();
        }
    };
    let result = crawlberg::generate_citations(&markdown_rs);
    Box::into_raw(Box::new(result))
}

